#!/bin/bash\n\n################################################################################\n# Script de Instalación del Proyecto en Termux\n# Versión: 1.0.0\n# Descripción: Copia el proyecto a Termux y prepara para compilación\n################################################################################\n\necho \"╔═══════════════════════════════════════════════════════════════╗\"\necho \"║  INSTALADOR DE PROYECTO PARA TERMUX                           ║\"\necho \"║  Versión 1.0.0                                               ║\"\necho \"╚═══════════════════════════════════════════════════════════════╝\"\necho \"\"\n\n# Detectar si estamos en Termux\nif [ ! -d \"$PREFIX\" ]; then\n    echo \"❌ Este script debe ejecutarse DENTRO de Termux\"\n    echo \"\"\n    echo \"Instrucciones:\"\n    echo \"1. Instala Termux desde Google Play Store\"\n    echo \"2. Abre Termux\"\n    echo \"3. Transfiere este script a Termux\"\n    echo \"4. Ejecuta: bash install-to-termux.sh\"\n    exit 1\nfi\n\necho \"✅ Termux detectado\"\necho \"\"\n\n# Variables\nPROJECT_NAME=\"gestor-creditos-app\"\nHOME_DIR=\"$HOME\"\nPROJECT_DIR=\"$HOME_DIR/$PROJECT_NAME\"\n\necho \"📁 Directorio de instalación: $PROJECT_DIR\"\necho \"\"\n\n# Paso 1: Actualizar Termux\necho \"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\"\necho \"Paso 1: Actualizando Termux...\"\necho \"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\"\npkg update -y\npkg upgrade -y\necho \"✅ Termux actualizado\"\necho \"\"\n\n# Paso 2: Instalar dependencias\necho \"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\"\necho \"Paso 2: Instalando dependencias...\"\necho \"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\"\npkg install -y nodejs npm git curl wget\necho \"✅ Dependencias instaladas\"\necho \"\"\n\n# Paso 3: Verificar instalación\necho \"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\"\necho \"Paso 3: Verificando instalación...\"\necho \"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\"\necho \"Node.js: $(node --version)\"\necho \"npm: $(npm --version)\"\necho \"git: $(git --version)\"\necho \"✅ Todas las herramientas instaladas\"\necho \"\"\n\n# Paso 4: Obtener el proyecto\necho \"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\"\necho \"Paso 4: Descargando proyecto...\"\necho \"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\"\n\nif [ -d \"$PROJECT_DIR\" ]; then\n    echo \"⚠️  El directorio $PROJECT_DIR ya existe\"\n    read -p \"¿Deseas reemplazarlo? (s/n): \" -n 1 -r\n    echo\n    if [[ $REPLY =~ ^[Ss]$ ]]; then\n        rm -rf \"$PROJECT_DIR\"\n        echo \"✅ Directorio anterior eliminado\"\n    else\n        echo \"❌ Operación cancelada\"\n        exit 1\n    fi\nfi\n\n# Opción A: Clonar desde GitHub\necho \"\"\necho \"Opciones de descarga:\"\necho \"1. Clonar desde GitHub (requiere URL)\"\necho \"2. Copiar desde almacenamiento compartido\"\necho \"3. Usar proyecto existente en Termux\"\nread -p \"Selecciona una opción (1-3): \" option\n\ncase $option in\n    1)\n        read -p \"Ingresa la URL del repositorio GitHub: \" repo_url\n        git clone \"$repo_url\" \"$PROJECT_DIR\"\n        ;;\n    2)\n        if [ -d \"$HOME/storage/downloads\" ]; then\n            read -p \"Ingresa el nombre del archivo ZIP: \" zip_file\n            unzip \"$HOME/storage/downloads/$zip_file\" -d \"$HOME_DIR\"\n            # Renombrar si es necesario\n            if [ -d \"$HOME_DIR/gestor-creditos-app-main\" ]; then\n                mv \"$HOME_DIR/gestor-creditos-app-main\" \"$PROJECT_DIR\"\n            fi\n        else\n            echo \"❌ Almacenamiento compartido no disponible\"\n            exit 1\n        fi\n        ;;\n    3)\n        if [ ! -d \"$PROJECT_DIR\" ]; then\n            echo \"❌ Proyecto no encontrado en $PROJECT_DIR\"\n            exit 1\n        fi\n        ;;\n    *)\n        echo \"❌ Opción inválida\"\n        exit 1\n        ;;\nesac\n\necho \"✅ Proyecto listo\"\necho \"\"\n\n# Paso 5: Hacer scripts ejecutables\necho \"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\"\necho \"Paso 5: Preparando scripts...\"\necho \"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\"\nchmod +x \"$PROJECT_DIR/setup-and-build-termux.sh\"\nchmod +x \"$PROJECT_DIR/compile-termux.sh\"\necho \"✅ Scripts preparados\"\necho \"\"\n\n# Paso 6: Mostrar resumen\necho \"╔═══════════════════════════════════════════════════════════════╗\"\necho \"║                                                               ║\"\necho \"║              ✅ INSTALACIÓN COMPLETADA ✅                    ║\"\necho \"║                                                               ║\"\necho \"╚═══════════════════════════════════════════════════════════════╝\"\necho \"\"\necho \"📁 Proyecto instalado en: $PROJECT_DIR\"\necho \"\"\necho \"🚀 PRÓXIMOS PASOS:\"\necho \"\"\necho \"1. Navega al directorio del proyecto:\"\necho \"   cd $PROJECT_DIR\"\necho \"\"\necho \"2. Ejecuta el script maestro:\"\necho \"   bash setup-and-build-termux.sh\"\necho \"\"\necho \"3. Espera 60-90 minutos mientras se compila\"\necho \"\"\necho \"4. Los APKs estarán en:\"\necho \"   $PROJECT_DIR/dist/apks/\"\necho \"\"\necho \"5. Instala los APKs en tu dispositivo\"\necho \"\"\necho \"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\"\necho \"\"\necho \"📞 Soporte: support@gestorcreditos.com\"\necho \"\"\necho \"¿Deseas comenzar la compilación ahora? (s/n)\"\nread -n 1 -r\necho\nif [[ $REPLY =~ ^[Ss]$ ]]; then\n    cd \"$PROJECT_DIR\"\n    bash setup-and-build-termux.sh\nelse\n    echo \"Para compilar más tarde, ejecuta:\"\n    echo \"cd $PROJECT_DIR && bash setup-and-build-termux.sh\"\nfi\n
